import{_ as e,o as d,c as r,ag as o}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"附录 A：推荐阅读路径","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/appendix-a.md","filePath":"chapters/appendix-a.md","lastUpdated":null}'),n={name:"chapters/appendix-a.md"};function a(l,t,c,s,i,p){return d(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="附录-a-推荐阅读路径" tabindex="-1">附录 A：推荐阅读路径 <a class="header-anchor" href="#附录-a-推荐阅读路径" aria-label="Permalink to &quot;附录 A：推荐阅读路径&quot;">​</a></h1><p>本书涵盖了 TensorRT-LLM 从入门到深度源码分析的各个方面。不同背景和目标的读者，可以根据自身需求选择最适合的阅读路径，而不必逐章顺序通读全书。以下提供四条典型路径供参考。</p><hr><h2 id="路径一-快速上手路径" tabindex="-1">路径一：快速上手路径 <a class="header-anchor" href="#路径一-快速上手路径" aria-label="Permalink to &quot;路径一：快速上手路径&quot;">​</a></h2><p><strong>适合读者：</strong> 希望尽快将 TensorRT-LLM 用起来的应用工程师、算法工程师。</p><p><strong>章节顺序：</strong> 第 1 章 → 第 5 章 → 第 6 章 → 第 10 章</p><table tabindex="0"><thead><tr><th>章节</th><th>内容</th><th>选取理由</th></tr></thead><tbody><tr><td>第 1 章：总体概览</td><td>TensorRT-LLM 的架构全貌、核心概念与代码仓库结构</td><td>建立整体认知，了解 <code>tensorrt_llm/</code> 顶层目录组织方式</td></tr><tr><td>第 5 章：模型定义与权重加载</td><td>以 LLaMA 为例讲解 <code>tensorrt_llm/models/llama/model.py</code> 中的模型定义，以及 <code>convert_checkpoint.py</code> 的权重转换流程</td><td>掌握如何将 HuggingFace 模型转换为 TensorRT-LLM 可用的 checkpoint</td></tr><tr><td>第 6 章：Engine 构建流程</td><td><code>trtllm-build</code> 命令的完整调用链，从 <code>tensorrt_llm/commands/build.py</code> 入口到 TensorRT Engine 序列化</td><td>学会构建 Engine，这是使用 TensorRT-LLM 最核心的一步</td></tr><tr><td>第 10 章：Python Runtime 与使用示例</td><td><code>tensorrt_llm/runtime/generation.py</code> 中的推理接口、<code>examples/</code> 下的典型用法</td><td>能够加载 Engine 并执行推理，跑通端到端流程</td></tr></tbody></table><p><strong>预期成果：</strong> 读完这四章后，读者可以独立完成「模型转换 → Engine 构建 → 推理部署」的完整流程。</p><hr><h2 id="路径二-深度理解路径" tabindex="-1">路径二：深度理解路径 <a class="header-anchor" href="#路径二-深度理解路径" aria-label="Permalink to &quot;路径二：深度理解路径&quot;">​</a></h2><p><strong>适合读者：</strong> 希望深入理解 TensorRT-LLM 内部实现机制的框架开发者、研究人员。</p><p><strong>章节顺序：</strong> 第 1 章 → 第 2 章 → 第 3 章 → ... → 第 19 章（全部章节顺序阅读）</p><table tabindex="0"><thead><tr><th>阶段</th><th>章节范围</th><th>核心内容</th></tr></thead><tbody><tr><td>基础篇</td><td>第 1 ~ 4 章</td><td>TensorRT 基础回顾、TensorRT-LLM 架构概览、Graph Rewriting 机制、<code>tensorrt_llm/graph_rewriting.py</code> 中的 pattern matching</td></tr><tr><td>模型篇</td><td>第 5 ~ 7 章</td><td>模型定义体系 (<code>tensorrt_llm/models/</code>)、Engine 构建流水线、Plugin 系统 (<code>cpp/tensorrt_llm/plugins/</code>)</td></tr><tr><td>运行时篇</td><td>第 8 ~ 11 章</td><td>C++ Runtime (<code>cpp/tensorrt_llm/runtime/</code>)、Batch Manager、调度策略、Python Runtime 封装</td></tr><tr><td>内核篇</td><td>第 12 ~ 14 章</td><td>Attention Kernel 实现 (<code>cpp/tensorrt_llm/kernels/</code>)、GEMM 优化、量化内核</td></tr><tr><td>分布式篇</td><td>第 15 ~ 16 章</td><td>Tensor Parallelism / Pipeline Parallelism 的通信原语、<code>cpp/tensorrt_llm/kernels/customAllReduceKernels/</code></td></tr><tr><td>工程篇</td><td>第 17 ~ 19 章</td><td>Triton 集成、性能分析方法论、生产环境最佳实践</td></tr></tbody></table><p><strong>预期成果：</strong> 全面掌握 TensorRT-LLM 从上层 Python API 到底层 CUDA Kernel 的完整实现，具备参与框架开发和提交 PR 的能力。</p><hr><h2 id="路径三-部署运维路径" tabindex="-1">路径三：部署运维路径 <a class="header-anchor" href="#路径三-部署运维路径" aria-label="Permalink to &quot;路径三：部署运维路径&quot;">​</a></h2><p><strong>适合读者：</strong> 负责将 LLM 推理服务部署到生产环境的 DevOps 工程师、SRE。</p><p><strong>章节顺序：</strong> 第 1 章 → 第 6 章 → 第 8 章 → 第 16 章 → 第 17 章 → 第 19 章</p><table tabindex="0"><thead><tr><th>章节</th><th>内容</th><th>选取理由</th></tr></thead><tbody><tr><td>第 1 章：总体概览</td><td>架构全貌与核心概念</td><td>理解系统边界，明确各组件的职责划分</td></tr><tr><td>第 6 章：Engine 构建流程</td><td><code>trtllm-build</code> 的参数体系与构建选项</td><td>掌握 <code>BuildConfig</code> 中影响部署的关键参数（如 <code>max_batch_size</code>、<code>max_input_len</code>），参见附录 B</td></tr><tr><td>第 8 章：C++ Runtime 架构</td><td><code>cpp/tensorrt_llm/runtime/gptSession.cpp</code> 中的会话管理、内存分配策略</td><td>了解 Runtime 的资源占用模式，便于容量规划</td></tr><tr><td>第 16 章：多卡分布式部署</td><td>Tensor Parallelism 和 Pipeline Parallelism 的部署拓扑、<code>mpirun</code> 启动方式</td><td>掌握多节点多卡部署方案</td></tr><tr><td>第 17 章：Triton Inference Server 集成</td><td><code>tensorrtllm_backend/</code> 的配置、<code>model_config.pbtxt</code> 编写</td><td>生产环境通常通过 Triton 对外提供服务</td></tr><tr><td>第 19 章：生产环境最佳实践</td><td>监控指标、故障排查、滚动升级策略</td><td>保障服务稳定运行的运维要点</td></tr></tbody></table><p><strong>预期成果：</strong> 能够独立完成从单卡到多卡、从测试到生产的完整部署流程，并建立有效的监控和运维体系。</p><hr><h2 id="路径四-性能优化路径" tabindex="-1">路径四：性能优化路径 <a class="header-anchor" href="#路径四-性能优化路径" aria-label="Permalink to &quot;路径四：性能优化路径&quot;">​</a></h2><p><strong>适合读者：</strong> 希望榨取最大推理性能的性能工程师、CUDA 开发者。</p><p><strong>章节顺序：</strong> 第 8 章 → 第 9 章 → 第 12 章 → 第 13 章 → 第 14 章 → 第 19 章</p><table tabindex="0"><thead><tr><th>章节</th><th>内容</th><th>选取理由</th></tr></thead><tbody><tr><td>第 8 章：C++ Runtime 架构</td><td>Runtime 内存管理、KV Cache 分配策略（<code>cpp/tensorrt_llm/runtime/kvCacheManager.cpp</code>）</td><td>理解推理过程中的内存瓶颈与调度开销</td></tr><tr><td>第 9 章：Batch Manager 与调度</td><td>In-flight Batching 实现（<code>cpp/tensorrt_llm/batch_manager/</code>）、请求调度策略</td><td>Batching 策略直接决定吞吐量上限</td></tr><tr><td>第 12 章：Attention Kernel 深度剖析</td><td>Flash Attention、Paged Attention 的 CUDA 实现（<code>cpp/tensorrt_llm/kernels/decoderMaskedMultiheadAttention/</code>）</td><td>Attention 是 LLM 推理中最关键的性能热点</td></tr><tr><td>第 13 章：GEMM 优化与量化</td><td>CUTLASS 集成、FP8/INT8/INT4 量化内核（<code>cpp/tensorrt_llm/kernels/cutlass_kernels/</code>）</td><td>GEMM 占据推理计算量的主要部分，量化是提升吞吐的利器</td></tr><tr><td>第 14 章：自定义 Kernel 开发</td><td>Plugin 开发流程、Kernel 注册机制（<code>cpp/tensorrt_llm/plugins/api/tllmPlugin.cpp</code>）</td><td>当内置优化不够时，能够开发自定义算子</td></tr><tr><td>第 19 章：生产环境最佳实践</td><td>性能 Profiling 方法论、<code>nsys</code> / <code>ncu</code> 使用技巧、端到端基准测试</td><td>将优化落地，用数据验证效果</td></tr></tbody></table><p><strong>预期成果：</strong> 深入理解 TensorRT-LLM 性能关键路径，能够通过参数调优、量化策略选择和自定义 Kernel 开发来最大化推理性能。</p><hr><blockquote><p><strong>提示：</strong> 无论选择哪条路径，都建议先通读第 1 章建立全局认知。各路径之间并不互斥，读者可以在完成一条路径后，按需补充其他路径的章节。</p></blockquote>',28)])])}const g=e(n,[["render",a]]);export{m as __pageData,g as default};
